+func TestTimelineRenderExpandedRejected(t *testing.T) {
+	now := time.Now()
+	tl := NewTimeline().
+		AddEvent("created", now, "user1", "").
+		AddEvent("rejected", now, "user2", "Not safe").
+		WithCurrent("rejected").
+		AsExpanded()
+
+	result := tl.Render()
+	if result == "" {
+		t.Error("Render returned empty string for rejected state")
+	}
+}
